INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.1.126','cb','cb.adi.1','ЧБ Ади 1.126',126,'মধ্যখণ্ডে, কৃষ্ণ-রাম—চৈতন্য-নিতাই ।
শ্যাম-শুক্ল-রূপ দেখিলেন শচী আই ॥১২৬॥','мадхйа-кхан̣д̣е, кр̣ш̣н̣а-на̄ма—чаитанйа-нита̄и
ш́йа̄ма-ш́укла-рӯпа декхилена ш́ачӣ а̄и',NULL,NULL),('cb.adi.1.127','cb','cb.adi.1','ЧБ Ади 1.127',127,'মধ্যখণ্ডে, চৈতন্যের মহা-পরকাশ ।
‘সাতপ্রহরিয়া ভাব’ ঐশ্বর্য্য-বিলাস ॥১২৭॥','мадхйа-кхан̣д̣е, чаитанйера маха̄-парака̄ш́а
‘са̄т-прахарийа̄ бха̄ва’ аиш́варйа-вила̄са',NULL,NULL),('cb.adi.1.128','cb','cb.adi.1','ЧБ Ади 1.128',128,'সেই দিন অ-মায়ায় কহিলেন কথা ।
যে-যে-সেবকের জন্ম হৈল যথা যথা ॥১২৮॥','сеи дина а-ма̄йа̄йа кахилена катха̄
йе-йе-севакера джанма хаила йатха̄ йатха̄',NULL,NULL),('cb.adi.1.129','cb','cb.adi.1','ЧБ Ади 1.129',129,'মধ্যখণ্ডে, নাচে বৈকুণ্ঠের নারায়ণ ।
নগরে নগরে কৈল আপনে কীর্ত্তন ॥১২৯॥','мадхйа-кхан̣д̣е, на̄че ваикун̣т̣хера на̄ра̄йан̣а
нагаре нагаре каила а̄пане кӣртана',NULL,NULL),('cb.adi.1.130','cb','cb.adi.1','ЧБ Ади 1.130',130,'মধ্যখণ্ডে, কাজীর ভাঙ্গিলা অহঙ্কার ।
নিজ-শক্তি প্রকাশিয়া কীর্ত্তন অপার ॥১৩০॥','мадхйа-кхан̣д̣е, ка̄джӣра бха̄н̇гила̄ ахан̇ка̄ра
ниджа-ш́акти прака̄ш́ийа̄ кӣртана апа̄ра',NULL,NULL),('cb.adi.1.131','cb','cb.adi.1','ЧБ Ади 1.131',131,'ভক্তি পাইল কাজী প্রভু-গৌরাঙ্গের বরে ।
স্বচ্ছন্দে কীর্ত্তন করে নগরে নগরে ॥১৩১॥','бхакти па̄ила ка̄джӣ прабху-гауран̇гера варе
сваччханде кӣртана каре нагаре нагаре',NULL,NULL),('cb.adi.1.132','cb','cb.adi.1','ЧБ Ади 1.132',132,'মধ্যখণ্ডে, মহাপ্রভু বরাহ হইয়া ।
নিজ-তত্ত্ব মুরারিরে কহিলা গর্জ্জিয়া ॥১৩২॥','мадхйа-кхан̣д̣е, маха̄прабху вара̄ха хаийа̄
ниджа-таттва мура̄рире кахила̄ гарджийа̄',NULL,NULL),('cb.adi.1.133','cb','cb.adi.1','ЧБ Ади 1.133',133,'মধ্যখণ্ডে, মুরারির স্কন্ধে আরোহণ ।
চতুর্ভুজ হঞা কৈলা অঙ্গনে ভ্রমণ ॥১৩৩॥','мадхйа-кхан̣д̣е, мура̄рира сканде а̄рохан̣а
чатур-бхуджа хан̃а каила̄ ан̇гане бхраман̣а',NULL,NULL),('cb.adi.1.134','cb','cb.adi.1','ЧБ Ади 1.134',134,'মধ্যখণ্ডে, শুক্লাম্বর-তণ্ডুল-ভোজন ।
মধ্যখণ্ডে, নানা ছান্দ হৈলা নারায়ণ ॥১৩৪॥','мадхйа-кхан̣д̣е, ш́укла̄мбара-тан̣д̣ула-бходжана
мадхйа-кхан̣д̣е, на̄на̄ чха̄нда хаила̄ на̄ра̄йан̣а',NULL,NULL),('cb.adi.1.135','cb','cb.adi.1','ЧБ Ади 1.135',135,'মধ্যখণ্ডে, রুক্মিণীর বেশে নারায়ণ ।
নাচিলেন, স্তন পিল সর্ব্ব ভক্তগণ ॥১৩৫॥','мадхйа-кхан̣д̣е, рукмин̣ӣра веш́е на̄ра̄йан̣а
на̄чилена, стана пила сарва бхакта-ган̣а',NULL,NULL),('cb.adi.1.136','cb','cb.adi.1','ЧБ Ади 1.136',136,'মধ্যখণ্ডে, মুকুন্দের দ সঙ্গ-দোষে ।
শেষে অনুগ্রহ কৈলা পরম সন্তোষে ॥১৩৬॥','мадхйа-кхан̣д̣е, мукундера дан̣д̣а сан̇га-дош̣е
ш́еш̣е ануграха каила̄ парама сантош̣е',NULL,NULL),('cb.adi.1.137','cb','cb.adi.1','ЧБ Ади 1.137',137,'মধ্যখণ্ডে, মহাপ্রভুর নিশায় কীর্ত্তন ।
বৎসরেক নবদ্বীপে কৈলা অনুক্ষণ ॥১৩৭॥','мадхйа-кхан̣д̣е, маха̄прабхура ниш́а̄йа кӣртана
ватсарека навадвӣпе каила̄ анукш̣ана',NULL,NULL),('cb.adi.1.138','cb','cb.adi.1','ЧБ Ади 1.138',138,'মধ্যখণ্ডে, নিত্যানন্দ-অদ্বৈত কৌতুক ।
অজ্ঞ-জনে বুঝে যেন কলহ-স্বরূপ ॥১৩৮॥','мадхйа-кхан̣д̣е, нитйа̄нанда-адваита каутука
аджн̃а-джане буджхе йена калаха-сварӯпа',NULL,NULL),('cb.adi.1.139','cb','cb.adi.1','ЧБ Ади 1.139',139,'মধ্যখণ্ডে, জননীর লক্ষ্যে ভগবান্ ।
বৈষ্ণবাপরাধ করাইলা সাবধান ॥১৩৯॥','мадхйа-кхан̣д̣е, джананӣра лакш̣йе бхагава̄н
ваиш̣н̣ава̄пара̄дха кара̄ила̄ са̄вадха̄на',NULL,NULL),('cb.adi.1.140','cb','cb.adi.1','ЧБ Ади 1.140',140,'মধ্যখণ্ডে, সকল-বৈষ্ণব জনে-জনে ।
সবে বর পাইলেন করিয়া স্তবনে ॥১৪০॥','мадхйа-кхан̣д̣е, сакала-ваиш̣н̣ава джане-джане
сабе вара па̄илена карийа̄ ставане',NULL,NULL),('cb.adi.1.141','cb','cb.adi.1','ЧБ Ади 1.141',141,'মধ্যখণ্ডে, প্রসাদ পাইলা হরিদাস ।
শ্রীধরের জলপান—কারুণ্য-বিলাস ॥১৪১॥','мадхйа-кхан̣д̣е, праса̄да па̄ила̄ харида̄са
ш́рӣдхарера джала-па̄на—ка̄рун̣йа-вила̄са',NULL,NULL),('cb.adi.1.142','cb','cb.adi.1','ЧБ Ади 1.142',142,'মধ্যখণ্ডে, সকল-বৈষ্ণব করি’ সঙ্গে ।
প্রতিদিন জাহ্নবীতে জলকেলি রঙ্গে ॥১৪২॥','мадхйа-кхан̣д̣е, сакала-ваиш̣н̣ава кари’ сан̇ге
прати-дина джа̄хнавӣте джала-кели ран̇ге',NULL,NULL),('cb.adi.1.143','cb','cb.adi.1','ЧБ Ади 1.143',143,'মধ্যখণ্ডে, গৌরচন্দ্র নিত্যানন্দ-সঙ্গে ।
অদ্বৈতের গৃহে গিয়াছিলা কোন রঙ্গে ॥১৪৩॥','мадхйа-кхан̣д̣е, гаурачандра нитйа̄нанда-сан̇ге
адваитера гр̣хе гийа̄чхила̄ кона ран̇ге',NULL,NULL),('cb.adi.1.144','cb','cb.adi.1','ЧБ Ади 1.144',144,'মধ্যখণ্ডে, অদ্বৈতেরে করি’ বহু দ ।
শেষে অনুগ্রহ কৈলা পরম-প্রচ ॥১৪৪॥','мадхйа-кхан̣д̣е, адваитера кари’ баху дан̣д̣а
ш́еш̣е ануграха каила̄ парама-прачан̣д̣а',NULL,NULL),('cb.adi.1.145','cb','cb.adi.1','ЧБ Ади 1.145',145,'মধ্যখণ্ডে, চৈতন্য-নিতাই—কৃষ্ণ-রাম ।
জানিলা মুরারি-গুপ্ত মহা-ভাগ্যবান্ ॥১৪৫॥','мадхйа-кхан̣д̣е, чаитанйа-нита̄и—кр̣ш̣н̣а-ра̄ма
джа̄нила̄ мура̄ри-гупта маха̄-бха̄гйава̄н',NULL,NULL),('cb.adi.1.146','cb','cb.adi.1','ЧБ Ади 1.146',146,'মধ্যখণ্ডে, দুইপ্রভু চৈতন্য-নিতাই ।
নাচিলেন শ্রীবাস-অঙ্গনে এক-ঠাঞি ॥১৪৬॥','мадхйа-кхан̣д̣е дуи прабху чаитанйа-нита̄и
на̄чилена ш́рӣва̄са-ан̇гане эка-т̣ха̄н̃и',NULL,NULL),('cb.adi.1.147','cb','cb.adi.1','ЧБ Ади 1.147',147,'মধ্যখণ্ডে, শ্রীবাসের মৃতপুত্ত্র-মুখে ।
জীবতত্ত্ব কহাইয়া ঘুচাইলা দুঃখে ॥১৪৭॥','мадхйа-кхан̣д̣е, ш́рӣва̄сера мр̣та-путра-мукхе
джӣва-таттва каха̄ийа̄ гхуча̄ила̄ дух̣кхе',NULL,NULL),('cb.adi.1.148','cb','cb.adi.1','ЧБ Ади 1.148',148,'চৈতন্যের অনুগ্রহে শ্রীবাস-পণ্ডিত ।
পাসরিলা পুত্ত্রশোক,—জগতে বিদিত ॥১৪৮॥','чаитанйера ануграхе ш́рӣва̄са-пан̣д̣ита
па̄сарила̄ путра-ш́оке,— джагате видита',NULL,NULL),('cb.adi.1.149','cb','cb.adi.1','ЧБ Ади 1.149',149,'মধ্যখণ্ডে, গঙ্গায় পড়িলা দুঃখ পাইয়া ।
নিত্যানন্দ-হরিদাস আনিল তুলিয়া ॥১৪৯॥','мадхйа-кхан̣д̣е, ган̇га̄йа пад̣ила̄ дух̣кха па̄ийа̄
нитйа̄нанда-харида̄са а̄нила тулийа̄',NULL,NULL),('cb.adi.1.150','cb','cb.adi.1','ЧБ Ади 1.150',150,'মধ্যখণ্ডে, চৈতন্যের অবশেষ-পাত্র ।
ব্রহ্মার দুর্ল্লভ নারায়ণী পাইলা মাত্র ॥১৫০॥','мадхйа-кхан̣д̣е, чаитанйера аваш́еш̣а-па̄тра
брахма̄ра дурлабха на̄ра̄йан̣ӣ па̄ила̄ ма̄тра',NULL,NULL),('cb.adi.1.151','cb','cb.adi.1','ЧБ Ади 1.151',151,'মধ্যখণ্ডে, সর্ব্বজীব উদ্ধার-কারণে ।
সন্ন্যাস করিতে প্রভু করিলা গমনে ॥১৫১॥','мадхйа-кхан̣д̣е, сарва-джӣва уддха̄ра-ка̄ран̣е
саннйа̄са карите прабху карила̄ гамане',NULL,NULL),('cb.adi.1.152','cb','cb.adi.1','ЧБ Ади 1.152',152,'কীর্ত্তন করিয়া ‘আদি’, অবধি ‘সন্ন্যাস’ ।
এই হৈতে কহি ‘মধ্যখণ্ডে’র বিলাস ॥১৫২॥','кӣртана карийа̄ ‘а̄ди’, авадхи ‘саннйа̄са’
эи хаите кахи ‘мадхйа-кхан̣д̣е’ра вила̄са',NULL,NULL),('cb.adi.1.153','cb','cb.adi.1','ЧБ Ади 1.153',153,'মধ্যখণ্ডে আছে আর কত-কোটি লীলা ।
বেদব্যাস বর্ণিবেন সে-সকল খেলা ॥১৫৩॥','мадхйа-кхан̣д̣е а̄чхе а̄ра ката-кот̣и лӣла̄
ведавйа̄са варн̣ибена се-сакала кхела̄',NULL,NULL),('cb.adi.1.154','cb','cb.adi.1','ЧБ Ади 1.154',154,'শেষখণ্ডে, বিশ্বম্ভর করিলা সন্ন্যাস ।
‘শ্রীকৃষ্ণচৈতন্য’-নাম তবে পরকাশ ॥১৫৪॥','ш́еш̣а-кхан̣д̣е, виш́вамбхара карила̄ саннйа̄са
‘ш́рӣ-кр̣ш̣н̣а-чаитанйа’ на̄ма табе парака̄ш́а',NULL,NULL),('cb.adi.1.155','cb','cb.adi.1','ЧБ Ади 1.155',155,'শেষখণ্ডে, শুনি’ প্রভুর শিখার মুন ।
বিস্তর করিলা প্রভু-অদ্বৈত ক্রন্দন ॥১৫৫॥','ш́еш̣а-кхан̣д̣е, ш́уни’ прабхура ш́икха̄ра мун̣д̣ана
вистара карила̄ прабху-адваита крандана',NULL,NULL),('cb.adi.1.156','cb','cb.adi.1','ЧБ Ади 1.156',156,'শেষখণ্ডে, শচী-দুঃখ—অকথ্য-কথন ।
চৈতন্য-প্রভাবে সবার রহিল জীবন ॥১৫৬॥','ш́еш̣а-кхан̣д̣е, ш́ачӣ-дух̣кха—акатхйа-катхана
чаитанйа-прабха̄ве саба̄ра рахила джӣвана',NULL,NULL),('cb.adi.1.157','cb','cb.adi.1','ЧБ Ади 1.157',157,'শেষখণ্ডে, নিত্যানন্দ চৈতন্যের দ ।
ভাঙ্গিলেন, বলরাম পরম-প্রচ ॥১৫৭॥','ш́еш̣а-кхан̣д̣е, нитйа̄нанда чаитанйера дан̣д̣а
бха̄н̇гилена, балара̄ма парама-прачан̣д̣а',NULL,NULL),('cb.adi.1.158','cb','cb.adi.1','ЧБ Ади 1.158',158,'শেষখণ্ডে, গৌরচন্দ্র গিয়া নীলাচলে ।
আপনারে লুকাই’ রহিলা কুতূহলে ॥১৫৮॥','ш́еш̣а-кхан̣д̣е, гаурачандра гийа̄ нӣла̄чале
а̄пана̄ре лука̄и’ рахила̄ кутӯхале',NULL,NULL),('cb.adi.1.159','cb','cb.adi.1','ЧБ Ади 1.159',159,'সার্ব্বভৌম-প্রতি আগে করি’ পরিহাস ।
শেষে সার্ব্বভৌমেরে ষভুজ-পরকাশ ॥১৫৯॥','са̄рвабхаума-прати а̄ге кари’ париха̄са
ш́еш̣е са̄рвабхаумере ш̣ад̣-бхуджа-парака̄ш́а',NULL,NULL),('cb.adi.1.160','cb','cb.adi.1','ЧБ Ади 1.160',160,'শেষখণ্ডে, প্রতাপরুদ্রেরে পরিত্রাণ ।
কাশীমিশ্র-গৃহেতে করিলা অধিষ্ঠান ॥১৬০॥','ш́еш̣а-кхан̣д̣е, прата̄парудрере паритра̄н̣а
ка̄ш́ӣ-миш́ра-гр̣хете карила̄ адхиш̣т̣ха̄на',NULL,NULL),('cb.adi.1.161','cb','cb.adi.1','ЧБ Ади 1.161',161,'দামোদর স্বরূপ, পরমানন্দ-পুরী ।
শেষখণ্ডে, এই দুই সঙ্গে অধিকারী ॥১৬১॥','да̄модара сварӯпа, парама̄нанда-пурӣ
ш́еш̣а-кхан̣д̣е, эи дуи сан̇ге адхика̄рӣ',NULL,NULL),('cb.adi.1.162','cb','cb.adi.1','ЧБ Ади 1.162',162,'শেষখণ্ডে, প্রভু পুনঃ আইলা গৌড়দেশে ।
